using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private DbContextOptions<SchoolContext> _options;

        [TestInitialize]
        public void Setup()
        {
            _options = TestHelpers.CreateDbOptions();
            TestHelpers.DrainNotificationQueue();
        }

        private void SeedStudents(params (string firstName, string lastName, DateTime enrollmentDate)[] students)
        {
            using var context = new SchoolContext(_options);
            foreach (var (firstName, lastName, enrollmentDate) in students)
            {
                context.Students.Add(new Student
                {
                    FirstMidName = firstName,
                    LastName = lastName,
                    EnrollmentDate = enrollmentDate
                });
            }
            context.SaveChanges();
        }

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithStudents()
        {
            SeedStudents(
                ("Alice", "Adams", new DateTime(2020, 9, 1)),
                ("Bob", "Baker", new DateTime(2021, 9, 1))
            );

            using var context = new SchoolContext(_options);
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            SeedStudents(
                ("Charlie", "Zebra", new DateTime(2020, 9, 1)),
                ("Alice", "Adams", new DateTime(2020, 9, 1)),
                ("Bob", "Miller", new DateTime(2020, 9, 1))
            );

            using var context = new SchoolContext(_options);
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;
            var model = (PaginatedList<Student>)result.Model;

            Assert.AreEqual("Adams", model[0].LastName);
            Assert.AreEqual("Miller", model[1].LastName);
            Assert.AreEqual("Zebra", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            SeedStudents(
                ("Alice", "Adams", new DateTime(2020, 9, 1)),
                ("Bob", "Zebra", new DateTime(2020, 9, 1))
            );

            using var context = new SchoolContext(_options);
            var controller = new StudentsController(context);

            var result = controller.Index("name_desc", null, null, null) as ViewResult;
            var model = (PaginatedList<Student>)result.Model;

            Assert.AreEqual("Zebra", model[0].LastName);
            Assert.AreEqual("Adams", model[1].LastName);
        }

        [TestMethod]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            SeedStudents(
                ("Alice", "Late", new DateTime(2022, 9, 1)),
                ("Bob", "Early", new DateTime(2019, 9, 1))
            );

            using var context = new SchoolContext(_options);
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, null, null) as ViewResult;
            var model = (PaginatedList<Student>)result.Model;

            Assert.AreEqual("Early", model[0].LastName);
            Assert.AreEqual("Late", model[1].LastName);
        }

        [TestMethod]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            SeedStudents(
                ("Alice", "Late", new DateTime(2022, 9, 1)),
                ("Bob", "Early", new DateTime(2019, 9, 1))
            );

            using var context = new SchoolContext(_options);
            var controller = new StudentsController(context);

            var result = controller.Index("date_desc", null, null, null) as ViewResult;
            var model = (PaginatedList<Student>)result.Model;

            Assert.AreEqual("Late", model[0].LastName);
            Assert.AreEqual("Early", model[1].LastName);
        }

        [TestMethod]
        public void Index_SearchByLastName_FiltersResults()
        {
            SeedStudents(
