    {
        private DbContextOptions<SchoolContext> _options;

        [TestInitialize]
        public void Setup()
        {
            _options = TestHelpers.CreateDbOptions();
            TestHelpers.DrainNotificationQueue();
        }

        private int SeedInstructorWithCourses()
        {
            using var context = new SchoolContext(_options);

            var dept = TestHelpers.CreateTestDepartment();
            context.Departments.Add(dept);
            context.SaveChanges();

            var course1 = new Course { CourseID = 101, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
            var course2 = new Course { CourseID = 102, Title = "Physics", Credits = 4, DepartmentID = dept.DepartmentID };
            context.Courses.AddRange(course1, course2);
            context.SaveChanges();

            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                LastName = "Smith",
                HireDate = new DateTime(2015, 9, 1),
                CourseAssignments = new List<CourseAssignment>
                {
                    new CourseAssignment { CourseID = 101 },
                    new CourseAssignment { CourseID = 102 }
                },
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            return instructor.ID;
        }

        private int SeedSimpleInstructor(string firstName = "Jane", string lastName = "Smith")
        {
            using var context = new SchoolContext(_options);
            var instructor = TestHelpers.CreateTestInstructor(firstName, lastName);
            context.Instructors.Add(instructor);
            context.SaveChanges();
            return instructor.ID;
        }

