        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Arrange - send some notifications
            using var svc = new NotificationService();
            svc.SendNotification("Student", "1", "Alice", EntityOperation.CREATE, "admin");
            svc.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "admin");

            using var context = new SchoolContext(_options);
            var controller = new NotificationsController(context);

            // Act
            var result = controller.GetNotifications() as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            var countProp = value.GetType().GetProperty("count");

            Assert.IsTrue((bool)successProp.GetValue(value));
            Assert.AreEqual(2, (int)countProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10()
        {
            // Arrange - send 15 notifications
            using var svc = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            using var context = new SchoolContext(_options);
            var controller = new NotificationsController(context);

            // Act
            var result = controller.GetNotifications() as JsonResult;

            // Assert
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
