            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.IsTrue((bool)successProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_DrainsQueueInFIFOOrder()
        {
            // Arrange
            using var svc = new NotificationService();
            svc.SendNotification("First", "1", EntityOperation.CREATE);
            svc.SendNotification("Second", "2", EntityOperation.UPDATE);

            using var context = new SchoolContext(_options);
            var controller = new NotificationsController(context);

            // Act
            var result = controller.GetNotifications() as JsonResult;

            // Assert
            var value = result.Value;
            var notificationsProp = value.GetType().GetProperty("notifications");
            var notifications = notificationsProp.GetValue(value) as System.Collections.Generic.List<Notification>;
            Assert.IsNotNull(notifications);
            Assert.AreEqual(2, notifications.Count);
            Assert.AreEqual("First", notifications[0].EntityType);
            Assert.AreEqual("Second", notifications[1].EntityType);
        }
    }
}

