            using (var context = new SchoolContext(_options))
            {
                context.Students.AddRange(
                    new Student { FirstMidName = "A", LastName = "A", EnrollmentDate = date1 },
                    new Student { FirstMidName = "B", LastName = "B", EnrollmentDate = date1 },
                    new Student { FirstMidName = "C", LastName = "C", EnrollmentDate = date2 }
                );
                context.SaveChanges();
            }

            using (var context = new SchoolContext(_options))
            {
                var controller = new HomeController(context);
                var result = (ViewResult)controller.About();
                var model = (System.Collections.Generic.List<Models.SchoolViewModels.EnrollmentDateGroup>)result.Model;

                var group1 = model.Single(g => g.EnrollmentDate == date1);
                var group2 = model.Single(g => g.EnrollmentDate == date2);

                Assert.AreEqual(2, group1.StudentCount);
                Assert.AreEqual(1, group2.StudentCount);
            }
        }
    }
}

