        private DbContextOptions<SchoolContext> _options;

        [TestInitialize]
        public void Setup()
        {
            _options = TestHelpers.CreateDbOptions();
            TestHelpers.DrainNotificationQueue();
        }

        private void SeedStudents(params (string firstName, string lastName, DateTime enrollmentDate)[] students)
        {
            using var context = new SchoolContext(_options);
            foreach (var (firstName, lastName, enrollmentDate) in students)
            {
                context.Students.Add(new Student
                {
                    FirstMidName = firstName,
                    LastName = lastName,
                    EnrollmentDate = enrollmentDate
                });
            }
            context.SaveChanges();
        }

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithStudents()
        {
            SeedStudents(
                ("Alice", "Adams", new DateTime(2020, 9, 1)),
                ("Bob", "Baker", new DateTime(2021, 9, 1))
            );

            using var context = new SchoolContext(_options);
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAscending()
