        public void Initialize_EmptyDatabase_SeedsCourseAssignments()
        {
            using var context = new SchoolContext(_options);

            DbInitializer.Initialize(context);

            Assert.AreEqual(8, context.CourseAssignments.Count());
        }

        [TestMethod]
        public void Initialize_AlreadySeeded_DoesNotAddMoreData()
        {
            // Arrange - add a student so the check passes
            using (var context = new SchoolContext(_options))
            {
                context.Students.Add(new Student
                {
                    FirstMidName = "Existing",
                    LastName = "Student",
                    EnrollmentDate = new DateTime(2020, 1, 1)
                });
                context.SaveChanges();
            }

            // Act - call Initialize on pre-seeded database
            using (var context = new SchoolContext(_options))
            {
                DbInitializer.Initialize(context);
            }

            // Assert - should still only have 1 student
            using var verifyCtx = new SchoolContext(_options);
            Assert.AreEqual(1, verifyCtx.Students.Count());
        }

        [TestMethod]
        public void Initialize_SeedsSpecificStudentNames()
        {
            using var context = new SchoolContext(_options);

            DbInitializer.Initialize(context);

            var studentNames = context.Students.Select(s => s.LastName).OrderBy(n => n).ToList();
            Assert.IsTrue(studentNames.Contains("Alexander"));
            Assert.IsTrue(studentNames.Contains("Alonso"));
            Assert.IsTrue(studentNames.Contains("Anand"));
            Assert.IsTrue(studentNames.Contains("Barzdukas"));
        }

        [TestMethod]
        public void Initialize_SeedsSpecificDepartmentNames()
        {
            using var context = new SchoolContext(_options);

            DbInitializer.Initialize(context);

            var deptNames = context.Departments.Select(d => d.Name).OrderBy(n => n).ToList();
            Assert.IsTrue(deptNames.Contains("English"));
            Assert.IsTrue(deptNames.Contains("Mathematics"));
            Assert.IsTrue(deptNames.Contains("Engineering"));
            Assert.IsTrue(deptNames.Contains("Economics"));
        }

        [TestMethod]
        public void Initialize_SeedsCoursesWithCorrectIds()
        {
            using var context = new SchoolContext(_options);

            DbInitializer.Initialize(context);

            Assert.IsNotNull(context.Courses.Find(1050)); // Chemistry
            Assert.IsNotNull(context.Courses.Find(4022)); // Microeconomics
            Assert.IsNotNull(context.Courses.Find(1045)); // Calculus
            Assert.IsNotNull(context.Courses.Find(2021)); // Composition
        }

        [TestMethod]
        public void Initialize_SeedsEnrollmentsWithGrades()
        {
            using var context = new SchoolContext(_options);

            DbInitializer.Initialize(context);

            // Some enrollments have grades, some don't
            var withGrades = context.Enrollments.Count(e => e.Grade != null);
            var withoutGrades = context.Enrollments.Count(e => e.Grade == null);
            Assert.IsTrue(withGrades > 0, "Expected some enrollments with grades");
            Assert.IsTrue(withoutGrades > 0, "Expected some enrollments without grades");
        }

        [TestMethod]
        public void Initialize_SetsDepartmentAdministrators()
        {
            using var context = new SchoolContext(_options);

            DbInitializer.Initialize(context);

            var departments = context.Departments.ToList();
            Assert.IsTrue(departments.All(d => d.InstructorID.HasValue),
                "All departments should have an administrator");
        }
    }
}

