+using Microsoft.VisualStudio.TestTools.UnitTesting;
+
+namespace ContosoUniversity.Tests.Services
+{
+    [TestClass]
+    public sealed class NotificationServiceTests
+    {
+        private NotificationService _service;
+
+        [TestInitialize]
+        public void Setup()
+        {
+            // Drain the static queue to avoid cross-test interference
+            using var drainer = new NotificationService();
+            while (drainer.ReceiveNotification() != null) { }
+
+            _service = new NotificationService();
+        }
+
+        [TestCleanup]
+        public void Cleanup()
+        {
+            _service?.Dispose();
+        }
+
+        [TestMethod]
+        public void SendNotification_EnqueuesNotification()
+        {
+            // Act
+            _service.SendNotification("Student", "1", EntityOperation.CREATE, "admin");
+
+            // Assert
+            var notification = _service.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("Student", notification.EntityType);
+            Assert.AreEqual("1", notification.EntityId);
+            Assert.AreEqual("CREATE", notification.Operation);
+            Assert.AreEqual("admin", notification.CreatedBy);
+            Assert.IsFalse(notification.IsRead);
+        }
+
+        [TestMethod]
+        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
+        {
+            // Act
+            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "admin");
+
+            // Assert
+            var notification = _service.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("New Course 'Chemistry' has been created", notification.Message);
+        }
+
+        [TestMethod]
+        public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
+        {
+            // Act
+            _service.SendNotification("Course", "101", EntityOperation.CREATE, "admin");
+
+            // Assert
+            var notification = _service.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("New Course (ID: 101) has been created", notification.Message);
+        }
+
+        [TestMethod]
+        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
+        {
+            _service.SendNotification("Student", "5", "John Doe", EntityOperation.UPDATE);
+
+            var notification = _service.ReceiveNotification();
+            Assert.AreEqual("Student 'John Doe' has been updated", notification.Message);
+        }
+
+        [TestMethod]
+        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
+        {
+            _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);
+
+            var notification = _service.ReceiveNotification();
+            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
+        }
+
+        [TestMethod]
+        public void SendNotification_DefaultUserName_IsSystem()
+        {
+            _service.SendNotification("Student", "1", EntityOperation.CREATE);
+
+            var notification = _service.ReceiveNotification();
+            Assert.AreEqual("System", notification.CreatedBy);
+        }
+
+        [TestMethod]
+        public void SendNotification_SetsCreatedAtToNow()
+        {
+            var before = DateTime.Now;
+
+            _service.SendNotification("Student", "1", EntityOperation.CREATE);
+
+            var after = DateTime.Now;
+            var notification = _service.ReceiveNotification();
+            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
+                $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
+        }
+
+        [TestMethod]
+        public void ReceiveNotification_EmptyQueue_ReturnsNull()
+        {
+            var result = _service.ReceiveNotification();
+
+            Assert.IsNull(result);
+        }
+
+        [TestMethod]
+        public void SendAndReceive_FIFO_Order()
+        {
+            // Arrange
+            _service.SendNotification("A", "1", EntityOperation.CREATE);
+            _service.SendNotification("B", "2", EntityOperation.UPDATE);
+            _service.SendNotification("C", "3", EntityOperation.DELETE);
+
+            // Act & Assert
+            var first = _service.ReceiveNotification();
+            Assert.AreEqual("A", first.EntityType);
+
+            var second = _service.ReceiveNotification();
+            Assert.AreEqual("B", second.EntityType);
+
+            var third = _service.ReceiveNotification();
+            Assert.AreEqual("C", third.EntityType);
+
+            var fourth = _service.ReceiveNotification();
+            Assert.IsNull(fourth);
+        }
+
