+using System.Collections.Generic;
+using System.Linq;
+using Microsoft.VisualStudio.TestTools.UnitTesting;
+
+namespace ContosoUniversity.Tests
+{
+    [TestClass]
+    public sealed class PaginatedListTests
+    {
+        [TestMethod]
+        public void Constructor_SetsPageIndex()
+        {
+            // Arrange & Act
+            var list = new PaginatedList<int>(new List<int> { 1, 2 }, 10, 2, 5);
+
+            // Assert
+            Assert.AreEqual(2, list.PageIndex);
+        }
+
+        [TestMethod]
+        public void Constructor_SetsTotalPages_ExactDivision()
+        {
+            // 10 items / page size 5 = 2 total pages
+            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
+
+            Assert.AreEqual(2, list.TotalPages);
+        }
+
+        [TestMethod]
+        public void Constructor_SetsTotalPages_RoundsUp()
+        {
+            // 10 items / page size 3 = ceil(3.33) = 4 total pages
+            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 3);
+
+            Assert.AreEqual(4, list.TotalPages);
+        }
+
+        [TestMethod]
+        public void Constructor_AddsItemsToList()
+        {
+            var items = new List<int> { 10, 20, 30 };
+
+            var list = new PaginatedList<int>(items, 20, 1, 5);
+
+            Assert.AreEqual(3, list.Count);
+            Assert.AreEqual(10, list[0]);
+            Assert.AreEqual(20, list[1]);
+            Assert.AreEqual(30, list[2]);
+        }
+
+        [TestMethod]
+        public void Constructor_EmptyItems_CreatesEmptyList()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 0, 1, 5);
+
+            Assert.AreEqual(0, list.Count);
+            Assert.AreEqual(0, list.TotalPages);
+        }
+
+        [TestMethod]
+        [DataRow(1, false, DisplayName = "Page 1 has no previous page")]
+        [DataRow(2, true, DisplayName = "Page 2 has previous page")]
+        [DataRow(3, true, DisplayName = "Page 3 has previous page")]
+        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
+        {
+            var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);
+
+            Assert.AreEqual(expected, list.HasPreviousPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_OnLastPage_ReturnsFalse()
+        {
+            // 10 items, page size 5 = 2 pages. Page 2 is last.
+            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
+
+            Assert.IsFalse(list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_NotOnLastPage_ReturnsTrue()
+        {
+            // 10 items, page size 5 = 2 pages. Page 1 is not last.
+            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
+
+            Assert.IsTrue(list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_SinglePage_ReturnsFalse()
+        {
+            // 3 items, page size 5 = 1 page. Page 1 is last.
+            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
+
+            Assert.IsFalse(list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_FirstPage_ReturnsCorrectItems()
+        {
+            var source = Enumerable.Range(1, 20).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 5);
+
+            Assert.AreEqual(5, result.Count);
+            Assert.AreEqual(1, result[0]);
+            Assert.AreEqual(5, result[4]);
+            Assert.AreEqual(1, result.PageIndex);
+            Assert.AreEqual(4, result.TotalPages);
+        }
+
+        [TestMethod]
+        public void Create_SecondPage_SkipsFirstPageItems()
+        {
+            var source = Enumerable.Range(1, 20).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 2, 5);
+
+            Assert.AreEqual(5, result.Count);
+            Assert.AreEqual(6, result[0]);
+            Assert.AreEqual(10, result[4]);
+            Assert.AreEqual(2, result.PageIndex);
+        }
+
+        [TestMethod]
+        public void Create_LastPage_ReturnsRemainingItems()
+        {
+            var source = Enumerable.Range(1, 12).AsQueryable();
+
+            // Page 3, size 5: items 11, 12
+            var result = PaginatedList<int>.Create(source, 3, 5);
+
+            Assert.AreEqual(2, result.Count);
+            Assert.AreEqual(11, result[0]);
+            Assert.AreEqual(12, result[1]);
+            Assert.AreEqual(3, result.PageIndex);
+            Assert.AreEqual(3, result.TotalPages);
+        }
+
+        [TestMethod]
+        public void Create_EmptySource_ReturnsEmptyList()
+        {
+            var source = Enumerable.Empty<int>().AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 5);
+
+            Assert.AreEqual(0, result.Count);
+            Assert.AreEqual(0, result.TotalPages);
+            Assert.AreEqual(1, result.PageIndex);
+        }
+
+        [TestMethod]
+        public void Create_SingleItem_HasCorrectPages()
+        {
+            var source = new List<int> { 42 }.AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 5);
+
+            Assert.AreEqual(1, result.Count);
+            Assert.AreEqual(42, result[0]);
+            Assert.AreEqual(1, result.TotalPages);
+            Assert.IsFalse(result.HasPreviousPage);
+            Assert.IsFalse(result.HasNextPage);
+        }
+    }
+}
