+namespace ContosoUniversity.Tests.Controllers
+{
+    [TestClass]
+    public sealed class NotificationsControllerTests
+    {
+        private DbContextOptions<SchoolContext> _options;
+
+        [TestInitialize]
+        public void Setup()
+        {
+            _options = TestHelpers.CreateDbOptions();
+            TestHelpers.DrainNotificationQueue();
+        }
+
+        [TestMethod]
+        public void Index_ReturnsViewResult()
+        {
+            using var context = new SchoolContext(_options);
+            var controller = new NotificationsController(context);
+
+            var result = controller.Index();
+
+            Assert.IsInstanceOfType(result, typeof(ViewResult));
+        }
+
+        [TestMethod]
+        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
+        {
+            using var context = new SchoolContext(_options);
+            var controller = new NotificationsController(context);
+
+            var result = controller.GetNotifications();
+
+            Assert.IsInstanceOfType(result, typeof(JsonResult));
+            var jsonResult = result as JsonResult;
+            Assert.IsNotNull(jsonResult.Value);
+
+            // Use reflection to check dynamic properties
+            var value = jsonResult.Value;
+            var successProp = value.GetType().GetProperty("success");
+            var countProp = value.GetType().GetProperty("count");
+
+            Assert.IsNotNull(successProp);
+            Assert.IsTrue((bool)successProp.GetValue(value));
+            Assert.AreEqual(0, (int)countProp.GetValue(value));
+        }
+
+        [TestMethod]
+        public void GetNotifications_WithNotifications_ReturnsNotifications()
+        {
+            // Arrange - send some notifications
+            using var svc = new NotificationService();
+            svc.SendNotification("Student", "1", "Alice", EntityOperation.CREATE, "admin");
+            svc.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "admin");
+
+            using var context = new SchoolContext(_options);
+            var controller = new NotificationsController(context);
+
+            // Act
+            var result = controller.GetNotifications() as JsonResult;
+
+            // Assert
+            Assert.IsNotNull(result);
+            var value = result.Value;
+            var successProp = value.GetType().GetProperty("success");
+            var countProp = value.GetType().GetProperty("count");
+
+            Assert.IsTrue((bool)successProp.GetValue(value));
+            Assert.AreEqual(2, (int)countProp.GetValue(value));
+        }
+
+        [TestMethod]
+        public void GetNotifications_LimitsTo10()
+        {
+            // Arrange - send 15 notifications
+            using var svc = new NotificationService();
+            for (int i = 0; i < 15; i++)
+            {
+                svc.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
+            }
+
+            using var context = new SchoolContext(_options);
+            var controller = new NotificationsController(context);
+
+            // Act
+            var result = controller.GetNotifications() as JsonResult;
+
+            // Assert
+            var value = result.Value;
+            var countProp = value.GetType().GetProperty("count");
+            Assert.AreEqual(10, (int)countProp.GetValue(value));
+        }
+
+        [TestMethod]
+        public void MarkAsRead_ReturnsSuccessJson()
+        {
+            using var context = new SchoolContext(_options);
+            var controller = new NotificationsController(context);
+
+            var result = controller.MarkAsRead(1) as JsonResult;
+
+            Assert.IsNotNull(result);
+            var value = result.Value;
+            var successProp = value.GetType().GetProperty("success");
+            Assert.IsTrue((bool)successProp.GetValue(value));
+        }
+
+        [TestMethod]
+        public void GetNotifications_DrainsQueueInFIFOOrder()
+        {
+            // Arrange
+            using var svc = new NotificationService();
+            svc.SendNotification("First", "1", EntityOperation.CREATE);
+            svc.SendNotification("Second", "2", EntityOperation.UPDATE);
+
+            using var context = new SchoolContext(_options);
+            var controller = new NotificationsController(context);
+
+            // Act
+            var result = controller.GetNotifications() as JsonResult;
+
+            // Assert
+            var value = result.Value;
+            var notificationsProp = value.GetType().GetProperty("notifications");
+            var notifications = notificationsProp.GetValue(value) as System.Collections.Generic.List<Notification>;
+            Assert.IsNotNull(notifications);
+            Assert.AreEqual(2, notifications.Count);
+            Assert.AreEqual("First", notifications[0].EntityType);
+            Assert.AreEqual("Second", notifications[1].EntityType);
+        }
+    }
+}
