+                context.Instructors.Add(instructor);
+                context.SaveChanges();
+                instructorId = instructor.ID;
+
+                var dept = new Department
+                {
+                    Name = "Test Dept",
+                    Budget = 100000m,
+                    StartDate = new DateTime(2020, 1, 1),
+                    InstructorID = instructorId
+                };
+                context.Departments.Add(dept);
+                context.SaveChanges();
+                deptId = dept.DepartmentID;
+            }
+
+            using (var context = new SchoolContext(_options))
+            {
+                var controller = new InstructorsController(context);
+                controller.DeleteConfirmed(instructorId);
+            }
+
+            using var verifyCtx = new SchoolContext(_options);
+            var department = verifyCtx.Departments.Find(deptId);
+            Assert.IsNull(department.InstructorID);
+        }
+
+        [TestMethod]
+        public void DeleteConfirmed_SendsNotification()
+        {
+            var id = SeedInstructorWithCourses();
+
+            using var context = new SchoolContext(_options);
+            var controller = new InstructorsController(context);
+            controller.DeleteConfirmed(id);
+
+            using var svc = new NotificationService();
+            var notification = svc.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("Instructor", notification.EntityType);
+            Assert.AreEqual("DELETE", notification.Operation);
+        }
+    }
+}
